    print(f"\n📋 {s['name']}")
    if "peak_kw_range" in s:
        print(f"   Demand Range: {s['peak_kw_range']} kW")
    if "peak_kw_min" in s:
        print(f"   Minimum Demand: {s['peak_kw_min']}+ kW")
    if "peak_kw_max" in s:
        print(f"   Maximum Demand: ≤{s['peak_kw_max']} kW")

    if "demand_charges" in s and isinstance(s["demand_charges"], str):
        print(f"   → {s['demand_charges']}")

    if "flat_demand" in s:
        for d in s["flat_demand"]:
            print(f"   → {d['period']}: ${d['total']:.3f}/kW  (base: ${d['base']:.3f} + adj: ${d['adj']:.3f})")
            if d['total'] > max_charge:
                max_charge = d['total']
                max_schedule = s['name']
                max_period = d['period']

    if "demand_rate" in s:
        for d in s["demand_rate"]:
            print(f"   → {d['period']}: ${d['total']:.3f}/kW  (base: ${d['base']:.3f} + adj: ${d['adj']:.3f})")
